import { describe, expect, it } from 'vitest';

import {
  adist,
  admitVitalSign,
  breathingEnv,
  noisyEnv,
  peakCount,
  staticEnv,
  totalMagnitude,
  totalVariation,
  VitalSignMaster,
  vitalSignRusticCertificate,
  zeroEnv,
  type Envelope,
} from '../src/vital-sign-micro-doppler';

const opts = { floor: 3, minPeaks: 1, maxPeaks: 3 } as const;

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(2, 5)).toBe(3);
    expect(adist(5, 2)).toBe(3);
    expect(adist(0, 9)).toBe(9);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 2 - 6)).toBe(0);
  });
});

describe('totalMagnitude (support metric)', () => {
  it('sums the residue magnitudes', () => {
    expect(totalMagnitude(breathingEnv)).toBe(24);
    expect(totalMagnitude(staticEnv)).toBe(28);
    expect(totalMagnitude(noisyEnv)).toBe(41);
    expect(totalMagnitude(zeroEnv)).toBe(0);
  });

  it('is zero on the empty envelope', () => {
    expect(totalMagnitude([])).toBe(0);
  });
});

describe('totalVariation (liveness gate, mirrors constEnv_variation_zero)', () => {
  it('a constant (static) envelope has zero total variation', () => {
    expect(totalVariation(staticEnv)).toBe(0);
  });

  it('a modulating envelope has positive total variation', () => {
    expect(totalVariation(breathingEnv)).toBe(20);
    expect(totalVariation(noisyEnv)).toBe(64);
  });

  it('sums successive residue distances', () => {
    // [2,5,2] -> |2-5| + |5-2| = 3 + 3 = 6
    expect(totalVariation([2, 5, 2])).toBe(6);
  });

  it('empty / singleton envelopes have zero variation', () => {
    expect(totalVariation([])).toBe(0);
    expect(totalVariation([4])).toBe(0);
  });
});

describe('peakCount (rate band, mirrors peakCount)', () => {
  it('counts local maxima (strictly greater than both neighbors)', () => {
    expect(peakCount(breathingEnv)).toBe(3);
    expect(peakCount(noisyEnv)).toBe(4);
  });

  it('a flat envelope has no peaks', () => {
    expect(peakCount(staticEnv)).toBe(0);
  });

  it('endpoints are never peaks (only one neighbor)', () => {
    // rising-then-falling single peak in the middle
    expect(peakCount([1, 9, 1])).toBe(1);
    // monotone sequences have no interior local maxima
    expect(peakCount([1, 2, 3, 4])).toBe(0);
    expect(peakCount([4, 3, 2, 1])).toBe(0);
  });

  it('plateaus are not strict peaks', () => {
    // [1,5,5,1] — neither 5 is strictly greater than its equal neighbor
    expect(peakCount([1, 5, 5, 1])).toBe(0);
  });

  it('empty / short envelopes have no peaks', () => {
    expect(peakCount([])).toBe(0);
    expect(peakCount([5])).toBe(0);
    expect(peakCount([5, 9])).toBe(0);
  });
});

describe('promotion check: admitVitalSign', () => {
  it('admits a supported, varying, in-band breathing residue', () => {
    // mirrors breathing_admitted
    const a = admitVitalSign(breathingEnv, opts);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.supported).toBe(true);
    expect(a.varied).toBe(true);
    expect(a.peakCount).toBe(3);
    expect(a.totalMagnitude).toBe(24);
    expect(a.totalVariation).toBe(20);
  });

  it('withholds a below-floor residue (no support)', () => {
    // mirrors zero_envelope_rejected
    const a = admitVitalSign(zeroEnv, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_support');
    expect(a.supported).toBe(false);
    expect(a.totalMagnitude).toBe(0);
  });

  it('withholds a supported but static residue (liveness gate)', () => {
    // mirrors static_body_rejected
    const a = admitVitalSign(staticEnv, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('static_body');
    expect(a.supported).toBe(true);
    expect(a.varied).toBe(false);
    expect(a.totalVariation).toBe(0);
  });

  it('downgrades a supported, varying but out-of-band residue to observation_only', () => {
    // mirrors noisy_out_of_band_rejected: motion present but not a clean rhythm
    const a = admitVitalSign(noisyEnv, opts);
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('rhythm_out_of_band');
    expect(a.supported).toBe(true);
    expect(a.varied).toBe(true);
    expect(a.peakCount).toBe(4);
  });

  it('too-few peaks is also out of band (below minPeaks)', () => {
    // a single-peak residue with a tightened band [2,3] is out of band below
    const single: Envelope = [1, 9, 1, 9, 1];
    // [1,9,1,9,1] -> peaks at index 1 and 3 => 2 peaks
    expect(peakCount(single)).toBe(2);
    const a = admitVitalSign(single, { floor: 3, minPeaks: 3, maxPeaks: 5 });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('rhythm_out_of_band');
  });

  it('support gate takes priority over liveness / band', () => {
    // a below-floor envelope is withheld for no_support even if it would vary
    const a = admitVitalSign([0, 1, 0], { floor: 3, minPeaks: 1, maxPeaks: 3 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_support');
  });
});

describe('VitalSignMaster (mirrors vital_sign_master)', () => {
  it('every boundary witness holds', () => {
    expect(VitalSignMaster.breathingAdmitted).toBe(true);
    expect(VitalSignMaster.staticRejected).toBe(true);
    expect(VitalSignMaster.noisyNotAdmitted).toBe(true);
    expect(VitalSignMaster.zeroRejected).toBe(true);
    expect(VitalSignMaster.breathingSupported).toBe(true);
    expect(VitalSignMaster.breathingVaried).toBe(true);
    expect(VitalSignMaster.breathingInBand).toBe(true);
    expect(VitalSignMaster.sameBodyDifferentVitalState).toBe(true);
    expect(VitalSignMaster.certRateBandGated).toBe(true);
    expect(VitalSignMaster.certStaticRejected).toBe(true);
  });

  it('the certificate records all gates', () => {
    expect(vitalSignRusticCertificate.residueModeled).toBe(true);
    expect(vitalSignRusticCertificate.supportGated).toBe(true);
    expect(vitalSignRusticCertificate.variationRequired).toBe(true);
    expect(vitalSignRusticCertificate.rateBandGated).toBe(true);
    expect(vitalSignRusticCertificate.staticRejected).toBe(true);
  });
});
